  { tag: 'meta', attrs: { property: 'og:url', content: 'https://hypestudy.com/' } },
  { tag: 'meta', attrs: { property: 'og:title', content: 'HypeStudy — Secure Study Platform for Students' } },
  { tag: 'meta', attrs: { property: 'og:description', content: 'Secure, animated, and modern study platform. Master your subjects with interactive flashcards, dynamic quizzes, comprehensive analytics, and powerful study tools.' } },
  { tag: 'meta', attrs: { property: 'og:image', content: 'logo.png' } },
  { tag: 'meta', attrs: { name: 'twitter:card', content: 'summary_large_image' } },
  { tag: 'meta', attrs: { name: 'twitter:site', content: '@hypestudy' } },
  { tag: 'meta', attrs: { name: 'twitter:title', content: 'HypeStudy — Secure Study Platform for Students' } },
  { tag: 'meta', attrs: { name: 'twitter:image', content: 'logo.png' } },
  { tag: 'link', attrs: { rel: 'icon', type: 'image/png', href: 'logo.png' } },
  { tag: 'link', attrs: { rel: 'apple-touch-icon', sizes: '180x180', href: 'logo.png' } },
  { tag: 'link', attrs: { rel: 'manifest', href: 'manifest.json' } },
  { tag: 'link', attrs: { rel: 'stylesheet', crossorigin: '', href: 'assets/index-wx3ZcHSz.css' } },
];
for (const nodeDef of headNodes) {
  const node = document.createElement(nodeDef.tag);
  for (const [name, value] of Object.entries(nodeDef.attrs)) node.setAttribute(name, value);
  document.head.appendChild(node);
}

